const raw = $json.stdout || $json.data || $json.response || '';

function trimToLines(text, limit) {
  return String(text || '')
    .split('\n')
    .map(l => l.trim())
    .filter(Boolean)
    .slice(0, limit);
}

function pickLines(lines, patterns, limit = 3) {
  const picked = [];
  for (const line of lines) {
    if (patterns.some((rx) => rx.test(line))) {
      picked.push(line);
    }
    if (picked.length >= limit) break;
  }
  return picked;
}

const lines = trimToLines(raw, 200);
const text = lines.join('\n');

const section = (start, end) => {
  const s = text.indexOf(start);
  if (s === -1) return '';
  const from = s + start.length;
  const e = end ? text.indexOf(end, from) : -1;
  return text.slice(from, e === -1 ? undefined : e).trim();
};

const hasJson = text.startsWith('{') || text.startsWith('[');
let parsed = null;
if (hasJson) {
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    parsed = null;
  }
}

const criticalPatterns = [ /critical/i, /sev[ -]?1/i, /p1/i, /outage/i, /down/i, /data loss/i ];
const warningPatterns = [ /high/i, /sev[ -]?2/i, /p2/i, /degraded/i, /latency/i, /error/i ];
const infoPatterns = [ /low/i, /sev[ -]?3/i, /p3/i, /info/i ];

let title = 'Ticket Analysis Report';
let summary = 'No structured ticket summary found in the source.';
let critical = [];
let warnings = [];
let info = [];
let actions = [];
let links = [];

if (parsed && typeof parsed === 'object') {
  title = parsed.title || parsed.name || title;
  summary = parsed.summary || parsed.executive_summary || summary;
  critical = Array.isArray(parsed.critical) ? parsed.critical : Array.isArray(parsed.critical_items) ? parsed.critical_items : [];
  warnings = Array.isArray(parsed.warnings) ? parsed.warnings : Array.isArray(parsed.warning_items) ? parsed.warning_items : [];
  info = Array.isArray(parsed.info) ? parsed.info : Array.isArray(parsed.info_items) ? parsed.info_items : [];
  actions = Array.isArray(parsed.actions) ? parsed.actions : Array.isArray(parsed.recommended_actions) ? parsed.recommended_actions : [];
  links = Array.isArray(parsed.links) ? parsed.links : [];
} else {
  critical = pickLines(lines, criticalPatterns, 5);
  warnings = pickLines(lines, warningPatterns, 5);
  info = pickLines(lines, infoPatterns, 5);
  actions = pickLines(lines, [/fix/i, /next step/i, /recommend/i, /action/i], 5);
  summary = lines.slice(0, 8).join(' ');
}

const overallStatus = critical.length ? 'Needs Immediate Attention' : warnings.length ? 'Monitor Closely' : 'Healthy';
const statusEmoji = critical.length ? '🚨' : warnings.length ? '⚠️' : '✅';

const safeText = (value, fallback = '—') => {
  const s = String(value ?? '').trim();
  return s.length ? s : fallback;
};

const bullets = (arr, fallback = 'None') => {
  if (!arr || !arr.length) return fallback;
  return arr.slice(0, 5).map((item) => `• ${safeText(item)}`).join('\n');
};

const linkCtx = links[0] || {};
const secondLink = links[1] || {};
const thirdLink = links[2] || {};

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `${statusEmoji} ${title}` }
  },
  {
    type: 'context',
    elements: [
      { type: 'mrkdwn', text: `*Status:* ${overallStatus}` },
      { type: 'mrkdwn', text: `*Checked:* ${new Date().toISOString()}` }
    ]
  },
  { type: 'divider' },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Summary*\n${safeText(summary)}` }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Critical*\n${critical.length}` },
      { type: 'mrkdwn', text: `*Warnings*\n${warnings.length}` },
      { type: 'mrkdwn', text: `*Info*\n${info.length}` },
      { type: 'mrkdwn', text: `*Actions*\n${actions.length}` }
    ]
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Critical Findings*\n${bullets(critical)}` }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Warnings*\n${bullets(warnings)}` }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Recommended Actions*\n${bullets(actions)}` }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Informational Items*\n${bullets(info)}` }
  }
];

if (linkCtx.url || secondLink.url || thirdLink.url) {
  blocks.push({
    type: 'context',
    elements: [
      { type: 'mrkdwn', text: `<${safeText(linkCtx.url, '#')}|${safeText(linkCtx.label, 'Source 1')}> • <${safeText(secondLink.url, '#')}|${safeText(secondLink.label, 'Source 2')}> • <${safeText(thirdLink.url, '#')}|${safeText(thirdLink.label, 'Source 3')}>` }
    ]
  });
}

return [{
  json: {
    title,
    overallStatus,
    critical,
    warnings,
    info,
    actions,
    summary,
    checkedAt: new Date().toISOString(),
    slackText: `${statusEmoji} ${title}: ${overallStatus}`,
    slackBlocks: blocks
  }
}];
